B.a_u=new A.m(B.v,"Yap\u0131 Kural\u0131","**Active:** Subject + **verb** + object\n**Passive:** Object + **be** + past participle (+ by + agent)\n\n**Tense mapping:**\n\u2022 Simple Present \u2192 is/are + V3\n\u2022 Simple Past \u2192 was/were + V3\n\u2022 Must/Should \u2192 must/should + be + V3\n\u2022 Has/Have \u2192 has/have + been + V3",null,null,null)
B.L=new A.pt(2,"examples")
B.RA=new A.a4(u.d,"Hidrolik pompa, motor taraf\u0131ndan di\u015fli kutusu arac\u0131l\u0131\u011f\u0131yla \xe7al\u0131\u015ft\u0131r\u0131l\u0131r.","is driven")
B.Qm=new A.a4("All maintenance tasks must be performed in accordance with the AMM.","T\xfcm bak\u0131m g\xf6revleri AMM'ye uygun \u015fekilde ger\xe7ekle\u015ftirilmelidir.","must be performed")
B.Sc=new A.a4("The fuel filter is replaced every 500 flight hours.","Yak\u0131t filtresi her 500 u\xe7u\u015f saatinde de\u011fi\u015ftirilir.","is replaced")
B.Qw=new A.a4("Warning notices must be placed in the cockpit before maintenance.","Bak\u0131mdan \xf6nce kokpite uyar\u0131 levhalar\u0131 yerle\u015ftirilmelidir.","must be placed")
B.aco=s([B.RA,B.Qm,B.Sc,B.Qw],t.l)
B.XU=new A.m(B.L,"Havac\u0131l\u0131k \xd6rnekleri",null,B.aco,null,null)
B.at=new A.pt(5,"tip")
B.a_1=new A.m(B.at,"\u2708\ufe0f S\u0131nav \u0130pucu",'\xc7oktan se\xe7meli sorularda ipucu ara:\n\u2022 \xd6zne bir **nesne** ise (ki\u015fi de\u011filse), b\xfcy\xfck ihtimalle edilgen \xe7at\u0131 do\u011frudur.\n\u2022 "\u2026\u2026\u2026\u2026 by the engine" \u2192 edilgen form gerekir.\n\u2022 Modal fiil + edilgen: **must be + ge\xe7mi\u015f zaman ortac\u0131** kal\u0131b\u0131 havac\u0131l\u0131k bak\u0131m \u0130ngilizcesinde en yayg\u0131n yap\u0131d\u0131r.',null,null,null)
B.a9=new A.e2(0,"grammar")
B.a7b=s(["drives","is driven","are driven","driving"],t.s)
B.p=new A.p_(0,"easy")
