B.a4d=s(["perform","must perform","must be performed","must performing"],t.s)
B.alx=new A.q(-2,B.a9,2,"All maintenance tasks \u2026\u2026\u2026\u2026 in accordance with the Aircraft Maintenance Manual.",B.a4d,2,B.p,null,null,null)
B.aeD=s(["places","placed","must be placed","must place"],t.s)
B.amF=new A.q(-3,B.a9,5,"The warning notice \u2026\u2026\u2026\u2026 in the cockpit to prevent operation of flight controls during maintenance.",B.aeD,2,B.p,null,null,null)
