B.YS=new A.m(B.x,"Resmi havac\u0131l\u0131k belgelerinin \xf6zel dil kal\u0131plar\u0131 vard\u0131r","Operasyon k\u0131lavuzlar\u0131, bak\u0131m k\u0131lavuzlar\u0131 (AMM) ve u\xe7u\u015fa elveri\u015flilik direktifleri, kesin hukuki ve teknik \xe7\u0131kar\u0131mlar i\xe7eren resmi \u0130ngilizce kullan\u0131r. Bu d\xfczeydeki \xe7eviri sorular\u0131, yaln\u0131zca kelimeleri de\u011fil, arkar\u0131ndaki **d\xfczenleyici amac\u0131** da anlamay\u0131 gerektirir.",null,null,null)
