B.Z5=new A.m(B.x,"Yasal metin dili neden farkl\u0131d\u0131r?",'EASA y\xf6netmelikleri, ICAO ekleri ve u\xe7u\u015f el kitaplar\u0131 belirli kal\u0131p ifadeler kullan\u0131r. "Shall", "must", "may", "should" gibi modal fiiller farkl\u0131 hukuki g\xfcce sahiptir. Bu fark\u0131 bilmek hem s\u0131navda hem ger\xe7ek operasyonda kritiktir.',null,null,null)
B.Zp=new A.m(B.v,"\u2696\ufe0f D\xfczenleyici Dilde Modal Fiil Hiyerar\u015fisi",'**SHALL** \u2192 zorunluluk (en g\xfc\xe7l\xfc ba\u011flay\u0131c\u0131)\n\u2192 "The operator shall ensure all crew hold valid licences."\n\u2192 T\xfcrk\xe7e: "\u2026 sa\u011flamak zorundad\u0131r / mecburidir"\n\n**MUST** \u2192 zorunluluk (\u015fart/gereklilik)\n\u2192 "Pilots must complete recurrent training annually."\n\u2192 T\xfcrk\xe7e: "\u2026 zorunludur / yapmal\u0131d\u0131r"\n\n**SHOULD** \u2192 tavsiye (zorunlu de\u011fil, beklenen)\n\u2192 "Crews should conduct a threat and error briefing before departure."\n\u2192 T\xfcrk\xe7e: "\u2026 yapmal\u0131 (tavsiye edilir)"\n\n**MAY** \u2192 izin / olas\u0131l\u0131k\n\u2192 "The commander may declare an emergency at his discretion."\n\u2192 T\xfcrk\xe7e: "\u2026 yapabilir / izinlidir"\n\n**IS REQUIRED TO** \u2192 zorunluluk (shall ile e\u015fde\u011fer)\n**IS PERMITTED TO** \u2192 izin (may ile e\u015fde\u011fer)\n**IS RECOMMENDED TO** \u2192 tavsiye (should ile e\u015fde\u011fer)',null,null,null)
B.Rd=new A.a4('"The commander shall satisfy himself that the aircraft is airworthy before commencing flight." (EASA ORO)',"Komutan, u\xe7u\u015fa ba\u015flamadan \xf6nce u\xe7a\u011f\u0131n u\xe7u\u015fa elveri\u015fli oldu\u011fundan emin olmak zorundad\u0131r.","shall satisfy himself that \u2026 airworthy")
B.R9=new A.a4('"Operators should implement fatigue risk management systems in accordance with Subpart FTL."',"\u0130\u015fleticilerin Subpart FTL'ye uygun yorgunluk riski y\xf6netim sistemi kurmalar\u0131 tavsiye edilmektedir.","should implement \u2026 in accordance with")
B.QN=new A.a4('"A commander may deviate from any rule to the extent necessary to meet an emergency situation." (ICAO Annex 2)',"Komutan, acil durumla ba\u015fa \xe7\u0131kmak i\xe7in gerekli \xf6l\xe7\xfcde herhangi bir kuraldan sapabilir.","may deviate \u2026 to the extent necessary")
