B.a1H=new A.m(B.x,"Acil durumda dil kesinli\u011fi hayat kurtar\u0131r",'Acil durum komutlar\u0131 **k\u0131sa, net ve teredd\xfcts\xfcz** olmal\u0131d\u0131r. Normal hizmet dilinin aksine, acil durumlarda "please" veya "would you mind" kullan\u0131lmaz \u2014 do\u011frudan emir kipi tercih edilir.\n\nEACCS (Emergency Aircraft Crew Communication System) standartlar\u0131na g\xf6re acil durum anonslar\u0131 uluslararas\u0131 standart ifadeler i\xe7erir.',null,null,null)
B.Xz=new A.m(B.v,"\u26a0\ufe0f Standart Acil Durum Komutlar\u0131",'**Brace komutu:**\n\u2022 "Brace! Brace! Brace!" \u2014 acil ini\u015f pozisyonu\n\u2022 "Head down! Stay down!"\n\n**Tahliye komutlar\u0131:**\n\u2022 "Release seatbelts! Come this way!"\n\u2022 "Leave everything! Get out!"\n\u2022 "Jump and slide!" (kayd\u0131raklarda)\n\n**Yang\u0131n/duman:**\n\u2022 "There is smoke in the cabin. Please remain calm and follow crew instructions."\n\n**T\u0131bbi:**\n\u2022 "Is there a doctor or medical professional on board?"\n\n**Kap\u0131 g\xfcvenli\u011fi:**\n\u2022 "Doors to manual and cross-check" / "Doors to automatic and cross-check"',null,null,null)
B.QH=new A.a4("Attention, this is an emergency. Fasten your seatbelts, put your seat backs and tray tables in their upright positions, and brace for impact.","Dikkat, bu bir acil durumdur. Emniyet kemerlerinizi ba\u011flay\u0131n, koltuk arkal\u0131klar\u0131n\u0131z\u0131 ve tepsi masalar\u0131n\u0131z\u0131 dik konuma getirin ve \xe7arpma i\xe7in haz\u0131r olun.","brace for impact")
B.RD=new A.a4("All passengers must evacuate the aircraft immediately. Leave all hand baggage behind and proceed to the nearest exit.","T\xfcm yolcular u\xe7aktan derhal tahliye edilmelidir. T\xfcm el bagajlar\u0131n\u0131z\u0131 geride b\u0131rak\u0131n ve en yak\u0131n \xe7\u0131k\u0131\u015fa do\u011fru ilerleyin.","Leave all hand baggage behind")
