B.a1A=new A.m(B.x,"Kabin servisi ileti\u015fimi","Kabin ekibinin yolcularla g\xfcnl\xfck ileti\u015fiminin \xf6nemli bir b\xf6l\xfcm\xfc ikram servisi s\u0131ras\u0131nda ger\xe7ekle\u015fir. Profesyonel ve net bir dil kullanmak yolcu memnuniyetini do\u011frudan etkiler.",null,null,null)
B.YC=new A.m(B.v,"Servis \u0130fadeleri",'"Would you like chicken or pasta for your main course?"\n"I\'m afraid we\'ve run out of chicken. Would you like pasta instead?"\n"Would you like something to drink?"\n"That would be [price]. Would you like to pay by card or cash?"\n"Your meal will be served shortly."\n"We will be coming through the cabin with duty-free items."\n"Please ensure your tray table is stowed and your seat is in the upright position for landing."',null,null,null)
