B.a_X=new A.m(B.x,"T\u0131bbi acil durumlar","Kabin ekibi bir t\u0131bbi acil durumla kar\u015f\u0131la\u015ft\u0131\u011f\u0131nda hem kaptana hem yerdeki t\u0131bbi destek hatt\u0131na hem de gerekirse ATC'ye net bilgi iletmek zorundad\u0131r. Yanl\u0131\u015f veya eksik bilgi do\u011fru m\xfcdahaleyi geciktirir.",null,null,null)
B.YY=new A.m(B.v,"T\u0131bbi Rapor \u0130fadeleri",'"Captain, we have a medical situation in row [X]. Passenger appears [conscious/unconscious]."\n"The passenger is [complaining of chest pain / having difficulty breathing / showing signs of allergic reaction]."\n"We have administered [oxygen / epinephrine / aspirin]."\n"Is there a doctor or medical professional on board?"\n"Medlink, this is [airline/flight number], we have a passenger with [symptoms], current position is [location]."\n"We request medical diversion to the nearest suitable airport."',null,null,null)
