B.a14=new A.m(B.x,"De-escalation neden \xf6nemlidir?","Disruptive passenger (rahats\u0131z edici yolcu) vakalar\u0131 hem u\xe7u\u015f g\xfcvenli\u011fini hem de di\u011fer yolcular\u0131 etkiler. Do\u011fru dil ve tutum, durumun daha da k\xf6t\xfcle\u015fmesini \xf6nler.",null,null,null)
B.a1h=new A.m(B.v,"De-escalation \u0130fadeleri",'"I understand your concern, sir/ma\'am. Let me see what I can do."\n"I\'m sorry for the inconvenience. We\'re doing our best to assist you."\n"I need you to return to your seat for the safety of all passengers."\n"If you continue this behaviour, the captain will be informed and we may have to divert."\n"I\'m going to have to ask you to comply with crew instructions."\n"We take the comfort and safety of all passengers very seriously."',null,null,null)
