B.XW=new A.m(B.x,"Crew rest neden \xf6nemlidir?","Uzun menzilli u\xe7u\u015flarda (genellikle 8 saati a\u015fan) kabin ekibine dinlenme f\u0131rsat\u0131 sa\u011flan\u0131r. Bu s\xfcrecin y\xf6netimi ve ileti\u015fimi belirli bir terminoloji gerektirir.",null,null,null)
B.WT=new A.m(B.v,"Crew Rest Terminolojisi",'**Crew rest compartment (CRC)** \u2014 ekip dinlenme b\xf6lmesi (\xfcst veya alt g\xfcverte)\n**Break schedule** \u2014 dinlenme takvimi\n**In-charge cabin crew member** \u2014 sorumlu kabin amiri\n\n\u0130fadeler:\n"I\'m going on my scheduled break. [Name] will be in charge."\n"Please call me if there is a medical emergency or if turbulence is forecast."\n"The crew will be taking turns resting. One senior crew member will remain in the cabin at all times."\n"We are approximately [X] hours from destination. Crew rest will begin shortly."',null,null,null)
B.a8Q=s(["the captain monitoring the cabin","the senior cabin crew responsible while others rest","a passenger volunteer","a relief pilot who monitors passengers"],t.s)
