B.abQ=s(["a more serious emergency","an urgency requiring assistance but not immediate danger to life","a routine communication","an engine failure"],t.s)
B.aoA=new A.q(-235,B.r,2105,'"PAN PAN" compared to "MAYDAY" indicates:',B.abQ,1,B.q,null,null,null)
