B.a0e=new A.m(B.x,"Teknik g\xfcnl\xfck nedir?","**Aircraft Technical Log (ATL)**, u\xe7akla birlikte seyahat eden ve her u\xe7u\u015f segmentinde doldurulmas\u0131 zorunlu olan belgedir. Ar\u0131zalar\u0131, yap\u0131lan i\u015flemleri ve u\xe7u\u015fa elveri\u015flilik beyan\u0131n\u0131 i\xe7erir.",null,null,null)
