B.a8g=s(["the engine lights up but does not accelerate to idle","the engine reaches full power too quickly","ignition fails completely","EGT is normal but N1 is high"],t.s)
B.apg=new A.q(-246,B.r,2116,'"Hung start" describes a condition where:',B.a8g,0,B.q,null,null,null)
