B.a2e=new A.m(B.x,"Modern aviyonik sistemler","Modern u\xe7aklarda aviyonik sistemler kendi kendini test edebilen (BITE \u2014 Built-In Test Equipment) \xf6zelli\u011fe sahiptir. AMT'nin bu sistemlerin \xe7\u0131kt\u0131lar\u0131n\u0131 anlayabilmesi ve ar\u0131za giderimini do\u011fru belgelemesi gerekir.",null,null,null)
B.Yh=new A.m(B.v,"Aviyonik Terminoloji",'**BITE** \u2014 Built-In Test Equipment: sistem i\xe7indeki otomatik test fonksiyonu\n**Fault code / fault message** \u2014 ar\u0131za kodu veya mesaj\u0131\n**LRU** \u2014 Line Replaceable Unit: sahada de\u011fi\u015ftirilebilen en k\xfc\xe7\xfck birim\n**Intermittent fault** \u2014 aral\u0131kl\u0131 ar\u0131za (s\xfcrekli tekrarlamayan)\n**Confirmed fault** \u2014 do\u011frulanm\u0131\u015f ar\u0131za (BITE s\xfcrekli kay\u0131t ediyor)\n**NFF** \u2014 No Fault Found: LRU de\u011fi\u015ftirildi fakat ar\u0131za bulunamad\u0131\n**ACMS** \u2014 Aircraft Condition Monitoring System\n**DFDR** \u2014 Digital Flight Data Recorder verisi\n\nTroubleshooting ifadeleri:\n"Access BITE menu on MCDU and retrieve active faults."\n"Fault confirmed: [LRU name] faulty. Replace LRU in accordance with AMM."\n"No fault found after LRU replacement. Monitor for recurrence."',null,null,null)
B.a4T=s(["the fault has been permanently resolved","the replaced LRU was defective","no defect was detected in the removed unit during bench test","the BITE system is faulty"],t.s)
B.amI=new A.q(-254,B.T,2124,'"NFF \u2014 No Fault Found" after LRU replacement means:',B.a4T,2,B.aV,null,null,null)
B.a7I=s(["is permanently active and easy to reproduce","appears and disappears without a clear pattern","was found only in the BITE test, not in flight","requires immediate AOG action"],t.s)
B.anM=new A.q(-255,B.T,2125,'An "intermittent fault" in avionics means the fault:',B.a7I,1,B.q,null,null,null)
