B.XQ=new A.m(B.x,"Yedek par\xe7a y\xf6netimi","AMT, bak\u0131m s\u0131ras\u0131nda do\u011fru par\xe7ay\u0131 tespit etmek, sipari\u015f etmek ve teslim al\u0131rken kontrol etmek zorundad\u0131r. Bu s\xfcrecin her ad\u0131m\u0131nda belirli bir terminoloji kullan\u0131l\u0131r.",null,null,null)
B.a1D=new A.m(B.v,"Par\xe7a Terminolojisi",'**P/N** \u2014 Part Number: par\xe7a numaras\u0131\n**S/N** \u2014 Serial Number: seri numaras\u0131\n**Batch/Lot Number** \u2014 seri \xfcretim parti numaras\u0131\n**Serviceable tag (Form 1 / 8130-3)** \u2014 par\xe7an\u0131n u\xe7u\u015fa elveri\u015fli oldu\u011funu g\xf6steren belge\n\u2014 EASA Form 1, FAA 8130-3\n**Unserviceable tag** \u2014 kullan\u0131lamaz etiketi\n**Shelf life** \u2014 raf \xf6mr\xfc\n**Cure date** \u2014 \xfcretim tarihi (lastik, conta i\xe7in)\n**Overhaul (OH)** \u2014 revizyon\n**Serviceable (SVC)** \u2014 u\xe7u\u015fa elveri\u015fli\n**Beyond Economical Repair (BER)** \u2014 ekonomik onar\u0131m s\u0131n\u0131r\u0131n\u0131 a\u015fm\u0131\u015f\n\n\u0130fadeler:\n"Verify P/N and S/N before installation."\n"Ensure valid EASA Form 1 accompanies the part."\n"Check shelf life has not expired prior to installation."',null,null,null)
