B.a_I=new A.m(B.x,"Servise verme sertifikas\u0131","**Certificate of Release to Service (CRS)**, bir bak\u0131m g\xf6revinin tamamland\u0131ktan sonra yetkili ki\u015fi taraf\u0131ndan imzalanmas\u0131 gereken belgedir. Bu belge olmadan u\xe7ak u\xe7u\u015fa al\u0131namaz.",null,null,null)
B.X_=new A.m(B.v,"CRS Dili",'**Standart CRS ifadesi (Part-145):**\n"Certifies that the work specified in this order has been carried out in accordance with Part-145 and in respect to that work the aircraft/aircraft component is considered ready for release to service."\n\n**Anahtar ifadeler:**\n\u2022 "released to service" \u2014 servise verildi\n\u2022 "in accordance with" (IAW) \u2014 uygun olarak\n\u2022 "approved data" \u2014 onayl\u0131 veri\n\u2022 "authorised certifying staff" \u2014 yetkili sertifikasyon personeli\n\u2022 "limitations as specified" \u2014 belirtilen s\u0131n\u0131rlamalar dahilinde\n\n**S\u0131n\u0131rl\u0131 release:**\n"Aircraft released to service with defect [X] deferred under MEL item [Y]."',null,null,null)
B.aap=s(["following","in accordance with","as per to","according"],t.s)
B.alN=new A.q(-258,B.Z,2128,'"The work has been carried out \u2026\u2026\u2026\u2026 Part-145 approved data."',B.aap,1,B.p,null,null,null)
B.ae9=s(["returned","cleared","released","approved"],t.s)
B.alp=new A.q(-259,B.Z,2129,'"Aircraft \u2026\u2026\u2026\u2026 to service." (CRS sonunda yaz\u0131lan standart ifade)',B.ae9,2,B.p,null,null,null)
